import torch
import torch.nn as nn
import torch.nn.functional as F


class Model(nn.Module):
    def __init__(self):
        super().__init__()
        self.mse_loss = nn.MSELoss()

    def forward(self, y_pred: torch.Tensor, y_true: torch.Tensor) -> torch.Tensor:
        # Unfolding the input to fit the dimensions required for MSELoss
        y_pred_unfolded = F.unfold(y_pred, kernel_size=(2, 2))
        y_true_unfolded = F.unfold(y_true, kernel_size=(2, 2))
        return self.mse_loss(y_pred_unfolded, y_true_unfolded)


